update e_user_data e set e.now_day_num = (select now_day_num from (select e_user_data.now_day_num from e_user_data where e_user_data.u_id = #{uId}) AS a) + 1, e.all_num = (select all_num from (select e_user_data.all_num from e_user_data where e_user_data.u_id = #{uId}) AS a) + 1
, e.now_day_complete = 1
where e.u_id = #{uId}

update e_user_data e set e.now_day_num = e.now_day_num + 1, e.all_num = e.all_num + 1
, e.now_day_complete = 1
where e.u_id = #{uId}
